class Solution:
    def maxSumTrionic(self, nums):
        n = len(nums)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + nums[i]
        NEG = float('-inf')
        best = NEG
        for p in range(1, n - 1):
            if nums[p - 1] >= nums[p]:
                continue
            # left starts: l in [incL, p-1]
            l = p
            while l > 0 and nums[l - 1] < nums[l]:
                l -= 1
            min_left = min(pre[t] for t in range(l, p))
            q = p
            while q + 1 < n and nums[q] > nums[q + 1]:
                q += 1
                # final rise from q
                r = q
                while r + 1 < n and nums[r] < nums[r + 1]:
                    r += 1
                    s = pre[r + 1] - min_left
                    if s > best:
                        best = s
        return best

