class Solution:
    def maxSumTrionic(self, nums):
        n = len(nums)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + nums[i]
        NEG = float('-inf')
        decR = [0] * n
        for i in range(n - 1, -1, -1):
            decR[i] = i if (i == n - 1 or nums[i] <= nums[i + 1]) else decR[i + 1]
        min_left = [None] * n
        for p in range(n):
            if p > 0 and nums[p - 1] < nums[p]:
                prev = min_left[p - 1]
                cand = pre[p - 1]
                min_left[p] = cand if prev is None else (prev if prev < cand else cand)
        max_right = [None] * n
        for q in range(n - 1, -1, -1):
            if q < n - 1 and nums[q] < nums[q + 1]:
                nxt = max_right[q + 1]
                cand = pre[q + 2]
                max_right[q] = cand if nxt is None else (nxt if nxt > cand else cand)
        best = NEG
        for p in range(n):
            mpl = min_left[p]
            if mpl is None:
                continue
            end = decR[p]
            for q in range(p + 1, end + 1):
                mr = max_right[q]
                if mr is None:
                    continue
                s = mr - mpl
                if s > best:
                    best = s
        return best

