var maxSumTrionic = function(nums) {
    const n = nums.length;
    const pre = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) pre[i + 1] = pre[i] + nums[i];
    const NEG = -Infinity;
    const decR = new Array(n).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        decR[i] = (i === n - 1 || nums[i] <= nums[i + 1]) ? i : decR[i + 1];
    }
    const minLeft = new Array(n).fill(null);
    for (let p = 0; p < n; p++) {
        if (p > 0 && nums[p - 1] < nums[p]) {
            const prev = minLeft[p - 1];
            const cand = pre[p - 1];
            minLeft[p] = prev === null ? cand : Math.min(prev, cand);
        }
    }
    const maxRight = new Array(n).fill(null);
    for (let q = n - 1; q >= 0; q--) {
        if (q < n - 1 && nums[q] < nums[q + 1]) {
            const nxt = maxRight[q + 1];
            const cand = pre[q + 2];
            maxRight[q] = nxt === null ? cand : Math.max(nxt, cand);
        }
    }
    let best = NEG;
    for (let p = 0; p < n; p++) {
        const mpl = minLeft[p];
        if (mpl === null) continue;
        const end = decR[p];
        for (let q = p + 1; q <= end; q++) {
            const mr = maxRight[q];
            if (mr === null) continue;
            const s = mr - mpl;
            if (s > best) best = s;
        }
    }
    return best;
};
